Anansi provides a unified API for standard CRUD (Create, Read, Update, Delete) operations, making it straightforward to interact with your data collections. All operations return Go's standard `error` type for error handling.

### Create Documents (`collection.Create`)

Use `collection.Create` to insert new documents into a collection. This method accepts either a single `map[string]any` or a slice of `[]map[string]any` for batch insertion.

```go
import (
	"time"
	"github.com/google/uuid"
	"go.uber.org/zap"
)

// Assuming 'userCollection' is an initialized persistence.PersistenceCollectionInterface

// 1. Create a single document
newUser := map[string]any{
    "id": uuid.New().String(),
    "username": "johndoe",
    "email": "john.doe@example.com",
    "created_at": time.Now(),
}

createdResult, err := userCollection.Create(newUser)
if err != nil {
    logger.Error("Failed to create user", zap.Error(err))
    // Handle specific errors, e.g., unique constraint violation from schema validation
    if validationErr, ok := err.(*schema.ValidationError); ok {
        // Process validation errors
    }
    return
}

// For a single document creation, createdResult will be a *query.QueryResult
// containing the newly inserted document's data and count (which will be 1).
if qr, ok := createdResult.(*query.QueryResult); ok && qr.Count == 1 {
    logger.Info("User created successfully", zap.Any("user_id", qr.Data.(schema.Document)["id"]))
} else {
    logger.Error("Unexpected result type after single create", zap.Any("result", createdResult))
}

// 2. Batch create multiple documents
batchUsers := []map[string]any{
    {
        "id": uuid.New().String(),
        "username": "janedoe",
        "email": "jane.doe@example.com",
        "created_at": time.Now(),
    },
    {
        "id": uuid.New().String(),
        "username": "peterpan",
        "email": "peter.pan@example.com",
        "created_at": time.Now(),
    },
}

batchResult, err := userCollection.Create(batchUsers)
if err != nil {
    logger.Error("Failed to batch create users", zap.Error(err))
    return
}

// For batch creation, batchResult will be a *query.QueryResult
// containing a slice of schema.Document for the inserted records.
if qr, ok := batchResult.(*query.QueryResult); ok && qr.Count > 0 {
    logger.Info("Batch users created successfully", zap.Int("count", qr.Count))
    for _, doc := range qr.Data.([]schema.Document) {
        logger.Info("  Inserted user", zap.Any("username", doc["username"]))
    }
} else {
    logger.Warn("No users created in batch, or unexpected result type", zap.Any("result", batchResult))
}
```

### Read Documents (`collection.Read`)

`collection.Read` is used to query documents. It takes a pointer to a `query.QueryDSL` object, which you construct using the fluent `query.NewQueryBuilder()` API. This allows for powerful filtering, sorting, and projection.

```go
import "github.com/asaidimu/go-anansi/v6/core/query"

// Assuming 'userCollection' is an initialized persistence.PersistenceCollectionInterface

// 1. Read all users, ordered by username ascending
allUsersQuery := query.NewQueryBuilder().OrderByAsc("username").Build()
result, err := userCollection.Read(&allUsersQuery)
if err != nil {
    logger.Error("Failed to read all users", zap.Error(err))
    return
}

if result.Count > 0 {
    fmt.Println("\n--- All Users (Ordered by Username) ---")
    if userDocs, ok := result.Data.([]schema.Document); ok {
        for _, userDoc := range userDocs {
            fmt.Printf("ID: %v, Username: %v, Email: %v\n", userDoc["id"], userDoc["username"], userDoc["email"])
        }
    } else if userDoc, ok := result.Data.(schema.Document); ok { // Handle case of single result
        fmt.Printf("ID: %v, Username: %v, Email: %v\n", userDoc["id"], userDoc["username"], userDoc["email"])
    }
} else {
    fmt.Println("No users found.")
}

// 2. Read a specific user by ID
specificUserQuery := query.NewQueryBuilder().Where("username").Eq("johndoe").Build()
userResult, err := userCollection.Read(&specificUserQuery)
if err != nil {
    logger.Error("Failed to read specific user", zap.Error(err))
    return
}

if userResult.Count == 1 {
    fmt.Println("\n--- Specific User ---")
    if userDoc, ok := userResult.Data.(schema.Document); ok {
        fmt.Printf("Found user: %v\n", userDoc["username"])
    } else {
        logger.Warn("Expected single document but got unexpected type after read by ID", zap.Any("data", userResult.Data))
    }
} else if userResult.Count == 0 {
    fmt.Println("User 'johndoe' not found.")
} else {
    logger.Warn("Unexpected count for specific user query", zap.Int("count", userResult.Count))
}
```

### Update Documents (`collection.Update`)

`collection.Update` modifies existing documents. It takes a `*persistence.CollectionUpdate` struct, which specifies the fields to update (`Data`) and a `query.QueryFilter` to select which documents to modify.

```go
import "github.com/asaidimu/go-anansi/v6/core/persistence"

// Assuming 'userCollection' is an initialized persistence.PersistenceCollectionInterface

// Update the email for 'johndoe'
updateData := map[string]any{
    "email": "john.doe.new@example.com",
}
updateFilter := query.NewQueryBuilder().Where("username").Eq("johndoe").Build().Filters

updateParams := &persistence.CollectionUpdate{
	Data:   updateData,
	Filter: updateFilter,
}

rowsAffected, err := userCollection.Update(updateParams)
if err != nil {
    logger.Error("Failed to update user email", zap.Error(err))
    return
}

logger.Info("User email updated", zap.Int("rows_affected", rowsAffected))

// You can verify the update by reading the user again
// ... (read user 'johndoe') ...
```

### Delete Documents (`collection.Delete`)

`collection.Delete` removes documents based on a `query.QueryFilter`. It includes a `unsafe` boolean flag for safety.

```go
// Assuming 'userCollection' is an initialized persistence.PersistenceCollectionInterface

// Delete the user 'peterpan'
deleteFilter := query.NewQueryBuilder().Where("username").Eq("peterpan").Build().Filters

// The 'false' parameter means 'unsafe' is false; a filter is required for deletion.
// Setting it to 'true' would allow deleting all documents without a filter (use with extreme caution).
rowsAffected, err := userCollection.Delete(deleteFilter, false)
if err != nil {
    logger.Error("Failed to delete user", zap.Error(err))
    return
}

logger.Info("User deleted", zap.Int("rows_affected", rowsAffected))

// Verify deletion by attempting to read the user
// ... (read user 'peterpan') ...
```

This section provides practical guides for common tasks using Anansi's API.

### Task 1: Building a Simple RESTful API Service

Anansi can be integrated into a web service to expose your data persistence layer via HTTP endpoints. The `examples/api` directory provides a basic RESTful API server implementation using Go's standard `net/http` package.

**Goal**: Create an API that allows creating, reading, updating, and deleting documents in collections, and managing collections themselves.

**Steps:**

1.  **Define API Request/Response Structures**: Create Go structs for your API payloads and responses. Anansi's `map[string]any` document representation works well with `encoding/json`.
    ```go
    // api.go (excerpt)
    type APIResponse struct {
        Success bool        `json:"success"`
        Data    any `json:"data,omitempty"`
        Error   *APIError   `json:"error,omitempty"`
    }

    type CollectionCreateRequest struct {
        Documents []map[string]any `json:"documents"`
    }

    // ... other request/response types
    ```

2.  **Initialize `APIServer`**: Instantiate `APIServer` with the Anansi persistence layer and a logger.
    ```go
    // main.go (from examples/api)
    // ... logger setup ...

    db, err := sql.Open("sqlite3", "./database.db")
    // ... error handling ...

    interactorOptions := sqlite.DefaultInteractorOptions()
    interactor := sqlite.NewSQLiteInteractor(db, logger, interactorOptions, nil)

    persistenceLayer, err := persistence.NewPersistence(interactor, nil)
    // ... error handling ...

    apiServer := NewAPIServer(persistenceLayer, logger)

    // Start server
    log.Println("Starting API server on :8080")
    if err := apiServer.Start(":8080"); err != nil {
        log.Fatal("Server failed:", err)
    }
    ```

3.  **Implement HTTP Handlers**: Map URL paths to functions that parse requests, interact with the `persistence.PersistenceCollectionInterface`, and return JSON responses.
    ```go
    // api.go (excerpt)
    func (s *APIServer) handleCollectionCreate(w http.ResponseWriter, r *http.Request, collectionName string) {
        var req CollectionCreateRequest
        if err := s.parseJSONBody(r, &req); err != nil {
            s.writeErrorResponse(w, http.StatusBadRequest, "INVALID_JSON", "Invalid JSON in request body", err.Error())
            return
        }

        collection, err := s.persistence.Collection(collectionName)
        if err != nil {
            s.writeErrorResponse(w, http.StatusNotFound, "COLLECTION_NOT_FOUND", fmt.Sprintf("Collection '%s' not found", collectionName), err.Error())
            return
        }

        results := make([]any, 0, len(req.Documents))
        for _, doc := range req.Documents {
            result, err := collection.Create(doc)
            if err != nil {
                s.writeErrorResponse(w, http.StatusInternalServerError, "CREATE_FAILED", "Failed to create document", err.Error())
                return
            }
            results = append(results, result)
        }
        s.writeSuccessResponse(w, http.StatusCreated, results)
    }

    // ... other handlers like handleCollectionRead, handleCollectionUpdate, etc.
    ```

4.  **Route Configuration**: Use `http.ServeMux` (or a router of your choice) to define API endpoints.
    ```go
    // api.go (excerpt)
    func (s *APIServer) setupRoutes() {
        s.mux.HandleFunc("/api/collections/", s.handleCollectionOperations)
        s.mux.HandleFunc("/api/collections/list", s.handleCollectionsList)
        // ... other routes
    }
    ```

**Example Interaction (using `curl` after starting `examples/api/main.go`):**

```bash
# 1. Create a collection schema
curl -X POST http://localhost:8080/api/collections/create -H "Content-Type: application/json" -d '{
  "schema": {
    "name": "products",
    "version": "1.0.0",
    "fields": {
      "id": { "name": "id", "type": "string", "required": true, "unique": true },
      "name": { "name": "name", "type": "string", "required": true },
      "price": { "name": "price", "type": "number", "required": true }
    },
    "indexes": [ { "fields": ["name"], "unique": true } ]
  }
}'

# 2. Create documents in the 'products' collection
curl -X POST http://localhost:8080/api/collections/products/create -H "Content-Type: application/json" -d '{
  "documents": [
    { "id": "prod-001", "name": "Laptop Pro", "price": 1200.00 },
    { "id": "prod-002", "name": "Wireless Mouse", "price": 25.50 }
  ]
}'

# 3. Read documents from 'products'
curl -X POST http://localhost:8080/api/collections/products/read -H "Content-Type: application/json" -d '{}'

# 4. Update a document
curl -X POST http://localhost:8080/api/collections/products/update -H "Content-Type: application/json" -d '{
  "filters": {
    "condition": { "field": "name", "operator": "eq", "value": "Laptop Pro" }
  },
  "data": { "price": 1150.00 }
}'

# 5. Delete a collection
curl -X POST http://localhost:8080/api/collections/delete -H "Content-Type: application/json" -d '{"name": "products"}'
```

### Task 2: Implementing Cross-Collection Logic with Event Subscriptions (Triggers)

Anansi's event system allows you to create reactive logic, similar to database triggers, where operations on one collection can automatically initiate actions on another. The `examples/intermediate/main.go` demonstrates an inventory management system where creating an order item automatically updates the inventory stock.

**Goal**: When a new `order_item` is created, reduce the `quantity` of the corresponding `inventory_item`.

**Steps:**

1.  **Define Schemas for Both Collections**: You'll need schemas for `inventory_items` and `order_items`.

2.  **Register a Subscription**: On the `order_items` collection, register a callback function for the `persistence.DocumentCreateSuccess` event.
    ```go
    // main.go (from examples/intermediate) excerpt

    // inventoryCollection and orderItemCollection are initialized PersistenceCollectionInterfaces

    subscriptionID := orderItemCollection.RegisterSubscription(persistence.RegisterSubscriptionOptions{
        Event: persistence.DocumentCreateSuccess, // Listen for successful order item creations
        Callback: func(ctx context.Context, event persistence.PersistenceEvent) error {
            // ... logic to extract order item details ...
            // ... logic to read current inventory item ...
            // ... logic to calculate new quantity ...

            newQuantity := currentQuantity - orderedQuantity
            if newQuantity < 0 {
                logger.Warn("Insufficient stock for item", zap.String("item_id", itemID))
                return fmt.Errorf("insufficient stock for item %s", itemID) // Returning an error prevents the original Create from committing (if part of Transact)
            }

            // Update the inventory item using the inventoryCollection
            updateData := map[string]any{
                "quantity":     newQuantity,
                "last_updated": time.Now(),
            }
            updateFilter := query.NewQueryBuilder().Where("id").Eq(itemID).Build().Filters

            updatedRows, err := inventoryCollection.Update(&persistence.CollectionUpdate{
                Data:   updateData,
                Filter: updateFilter,
            })
            if err != nil {
                logger.Error("Failed to update inventory quantity", zap.String("item_id", itemID), zap.Error(err))
                return err
            }
            logger.Info("Inventory updated successfully", zap.String("item_id", itemID), zap.Int("rows_affected", updatedRows), zap.Int64("new_quantity", newQuantity))

            return nil
        },
    })
    logger.Info("Subscription registered for 'order_items' DocumentCreateSuccess events.", zap.String("subscription_id", subscriptionID))
    ```

3.  **Perform Operations**: When you `Create` a document in `order_items`, the registered subscription callback will automatically execute, updating the `inventory_items` collection. The example shows how returning an error from the callback (`return fmt.Errorf(...)`) can effectively prevent an order from going through if stock is insufficient, showcasing rudimentary transactional behavior (though full `Transact` should be used for atomic multi-collection operations).

**Key Takeaway**: Subscriptions enable powerful, decoupled event-driven architectures within your Anansi application. They are ideal for implementing business rules, auditing, caching invalidation, or integrating with external systems based on data changes.

Anansi provides several advanced features for complex scenarios, customization, and optimization.

### 1. In-memory Go Functions (Computed Fields & Custom Filters)

Anansi allows you to extend its querying capabilities by registering custom Go functions that operate on data **in-memory** after it's fetched from the database. This is particularly useful for logic that is difficult or impossible to express in standard SQL, or for processing nested JSON data efficiently.

#### How it Works:

*   **`query.ComputeFunction`**: Transforms existing fields or adds new 'computed' fields to documents. The function receives the current `schema.Document` (row) and arguments defined in the query DSL.
*   **`query.PredicateFunction`**: Implements custom filtering logic. The function receives a `schema.Document`, a field name, and arguments, returning `true` if the document matches the filter, `false` otherwise.

#### Registration:

You register these functions via a `schema.FunctionMap` when initializing the `persistence.NewPersistence` service:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"os"

	"github.com/asaidimu/go-anansi/v6/core/persistence"
	"github.com/asaidimu/go-anansi/v6/core/query"
	"github.com/asaidimu/go-anansi/v6/core/schema"
	"github.com/asaidimu/go-anansi/v6/sqlite"
	_ "github.com/mattn/go-sqlite3"
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
)

func main() {
	// ... logger and database setup ...

	// 1. Define your schema, potentially with 'object' or 'record' fields for nested JSON
	// (e.g., a 'properties' field of type 'object')

	// 2. Prepare the FunctionMap with your custom Go functions
	customFunctions := schema.FunctionMap{
		"full_product_name": query.ComputeFunction(func(row schema.Document, args query.FilterValue) (any, error) {
			// Example: Combines product_name and a nested 'color' property
			pName, ok := row["product_name"].(string)
			if !ok { return nil, fmt.Errorf("product_name not string") }
			if props, ok := row["properties"].(map[string]any); ok {
				if color, ok := props["color"].(string); ok {
					return fmt.Sprintf("%s (%s)", pName, color), nil
				}
			}
			return pName, nil
		}),
		"is_premium": query.PredicateFunction(func(doc schema.Document, field string, args query.FilterValue) (bool, error) {
			// Example: Custom filter to check if 'properties.tier' is "premium"
			if props, ok := doc["properties"].(map[string]any); ok {
				if tier, ok := props["tier"].(string); ok {
					return tier == "premium", nil
				}
			}
			return false, nil
		}),
	}

	// 3. Initialize Persistence with the custom functions
	interactorOptions := sqlite.DefaultInteractorOptions()
	interactor := sqlite.NewSQLiteInteractor(db, logger, interactorOptions, nil)
	persistenceService, err := persistence.NewPersistence(interactor, customFunctions)
	if err != nil {
		logger.Fatal("Failed to initialize persistence", zap.Error(err))
	}
	// ... rest of your application logic ...
}
```

#### Usage in Queries:

*   **Computed Fields**: Use `Select().AddComputed(alias, functionName, args...)` in your `QueryBuilder`.

    ```go
    // Query using the registered Compute Function
    qWithGoFuncs := query.NewQueryBuilder().
        // Ensure fields needed by the compute function are selected from DB
        Select().Include("id", "product_name", "properties").
            AddComputed("full_display_name", "full_product_name"). // 'full_product_name' is the registered function name
        End().
        Build()

    result, err := collection.Read(&qWithGoFuncs)
    // ... process results, 'full_display_name' will be a new field in your documents
    ```

*   **Custom Filters**: Use `Where(field).Custom(operatorName, args)` in your `QueryBuilder`.

    ```go
    // Query using the custom Go filter
    qWithGoFilter := query.NewQueryBuilder().
        Where("id").Custom("is_premium", nil). // 'is_premium' is the registered predicate function name
        Select().Include("id", "product_name", "properties"). // Ensure 'properties' is fetched for filter to work
        End().
        Build()

    resultFilter, err := collection.Read(&qWithGoFilter)
    // ... process results, only premium products will be returned
    ```

**Optimization Note**: Go-based functions execute *after* initial database retrieval. For very large datasets, combine them with efficient SQL filters to reduce the amount of data processed in memory.

### 2. Transaction Management (`persistence.Transact`)

For atomic operations involving multiple persistence actions (e.g., creating an order and updating inventory), use `persistence.Transact`. This ensures that all operations either succeed or fail together, maintaining data consistency.

```go
import (
	"context"
	"fmt"
	"time"
	"github.com/google/uuid"
	"go.uber.org/zap"
)

// Assuming 'persistenceSvc' is your initialized PersistenceInterface
// and 'inventoryCollection' is obtained via persistenceSvc.Collection("inventory_items")

_, err = persistenceSvc.Transact(func(tx persistence.PersistenceTransactionInterface) (any, error) {
    // Get collection handles *within* the transaction context
    txInventoryCollection, err := tx.Collection("inventory_items")
    if err != nil { return nil, fmt.Errorf("failed to get transactional inventory collection: %w", err) }
    txOrderCollection, err := tx.Collection("order_items") // Assuming 'order_items' collection exists
    if err != nil { return nil, fmt.Errorf("failed to get transactional order collection: %w", err) }

    // 1. Create a new order item
    newOrderID := uuid.New().String()
    orderItemData := map[string]any{
        "id":               uuid.New().String(),
        "item_id":          "laptop-uuid", // Reference to an existing laptop item
        "ordered_quantity": int64(2),
        "order_id":         newOrderID,
        "created_at":       time.Now(),
    }
    _, err = txOrderCollection.Create(orderItemData)
    if err != nil { return nil, fmt.Errorf("failed to create order item: %w", err) }

    // 2. Read current stock of the ordered item
    inventoryQuery := query.NewQueryBuilder().Where("id").Eq("laptop-uuid").Build()
    inventoryResult, err := txInventoryCollection.Read(&inventoryQuery)
    if err != nil { return nil, fmt.Errorf("failed to read inventory: %w", err) }

    if inventoryResult.Count == 0 || inventoryResult.Data == nil { return nil, fmt.Errorf("item not found in inventory") }

    currentInventory, ok := inventoryResult.Data.(schema.Document)["quantity"].(int64)
    if !ok { return nil, fmt.Errorf("invalid quantity type in inventory") }

    if currentInventory < orderItemData["ordered_quantity"].(int64) {
        return nil, fmt.Errorf("insufficient stock for item") // This error will cause rollback
    }

    // 3. Update inventory stock
    updatedQuantity := currentInventory - orderItemData["ordered_quantity"].(int64)
    updateData := map[string]any{
        "quantity":     updatedQuantity,
        "last_updated": time.Now(),
    }
    updateFilter := query.NewQueryBuilder().Where("id").Eq("laptop-uuid").Build().Filters
    _, err = txInventoryCollection.Update(&persistence.CollectionUpdate{
        Data: updateData,
        Filter: updateFilter,
    })
    if err != nil { return nil, fmt.Errorf("failed to update inventory: %w", err) }

    logger.Info("Transaction operations successful, committing...")
    return map[string]any{"order_id": newOrderID, "status": "processed"}, nil
}) 

if err != nil {
    logger.Error("Transaction failed: operations rolled back", zap.Error(err))
} else {
    logger.Info("Transaction committed successfully.")
}
```

**Key Points:**

*   The `callback` function receives `persistence.PersistenceTransactionInterface`, ensuring all operations performed within it are part of the same database transaction.
*   If the `callback` returns an `error`, the transaction is automatically rolled back, discarding all changes. Otherwise, it's committed.
*   This mechanism is crucial for maintaining data integrity across multiple operations.

### 3. Advanced QueryDSL Features

Anansi's `query.QueryBuilder` allows for highly expressive and powerful queries beyond simple equality filters. Here's a deeper dive into its capabilities:

#### Filtering with Nested Logic (AND/OR Groups)

You can combine multiple conditions using logical `AND` or `OR` operators, and even nest these groups.

```go
import "github.com/asaidimu/go-anansi/v6/core/query"

// Find users who are either 'active' AND (live in 'New York' OR 'Los Angeles')
complexQuery := query.NewQueryBuilder().
    Where("status").Eq("active").
    WhereGroup(schema.LogicalOr). // Start an OR group
        Where("city").Eq("New York").
        Where("city").Eq("Los Angeles").
    End(). // End the OR group
    Build()

results, err := userCollection.Read(&complexQuery)
// ...
```

#### Pagination (Limit and Offset)

Control the number of results and their starting point for pagination.

```go
// Get the second page of users, with 10 users per page
paginatedQuery := query.NewQueryBuilder().
    OrderByAsc("username"). // Important for consistent pagination
    Limit(10).Offset(10).   // Limit 10 records, skip first 10 (page 2)
    Build()

results, err := userCollection.Read(&paginatedQuery)
// ...
```

#### Projection (Include/Exclude Specific Fields)

Optimize data retrieval by specifying exactly which fields you want to include or exclude from the results.

```go
// Get only username and email, exclude 'created_at'
projectedQuery := query.NewQueryBuilder().
    Select().
        Include("username", "email").
        // Exclude("password_hash"). // You can also exclude fields
    End().
    Build()

results, err := userCollection.Read(&projectedQuery)
// ... results will only contain 'username' and 'email'
```

#### Query Hints

Pass optimization hints to the underlying database (behavior depends on the `DatabaseInteractor` implementation).

```go
// Hint SQLite to use a specific index and set a max execution time
hintedQuery := query.NewQueryBuilder().
    Where("email").Eq("test@example.com").
    UseIndex("idx_users_email").
    MaxExecutionTime(5). // Max 5 seconds for query execution
    Build()

results, err := userCollection.Read(&hintedQuery)
// ...
```

### 4. Schema Versioning and Migrations (Planned)

Anansi's `schema.Migration` concept and methods like `persistence.PersistenceInterface.Migrate` and `Rollback` are designed to support declarative schema evolution. While current implementations in SQLite are placeholders, the framework is built to allow:

*   Defining incremental schema changes (add/remove/modify fields, indexes, constraints).
*   Specifying data transformation functions (`schema.TransformFunction`) to convert existing data when schema changes occur.
*   Applying and rolling back migrations in a controlled manner.

This will provide a robust mechanism for managing your data's lifecycle as your application evolves. Details will be fully available as these features are implemented.

initializationPatterns.codeExample:
package main

import (
	"database/sql"
	"log"

	"github.com/asaidimu/go-anansi/v6/core/persistence"
	"github.com/asaidimu/go-anansi/v6/core/schema"
	"github.com/asaidimu/go-anansi/v6/sqlite"
	_ "github.com/mattn/go-sqlite3" // SQLite driver
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
)

func main() {
	// Configure Zap logger for structured logging
	config := zap.NewProductionConfig()
	config.Level = zap.NewAtomicLevelAt(zapcore.InfoLevel)       // Set minimum logging level
	config.EncoderConfig.EncodeTime = zapcore.ISO8601TimeEncoder // Human-readable timestamps
	logger, err := config.Build()
	if err != nil {
		log.Fatalf("Failed to initialize logger: %v", err)
	}
	defer logger.Sync() // Ensure all buffered logs are written

	// 1. Open SQLite database connection. './data.db' will create a file-based database.
	db, err := sql.Open("sqlite3", "./data.db")
	if err != nil {
		logger.Fatal("Failed to open database", zap.Error(err))
	}
	defer db.Close() // Ensure the database connection is closed when main exits

	// 2. Initialize SQLite Interactor with default options.
	// Default options are generally safe for production unless specific behaviors are needed.
	interactorOptions := sqlite.DefaultInteractorOptions()
	// For development, consider: interactorOptions.DropIfExists = true // DANGER: Wipes DB on startup
	interactor := sqlite.NewSQLiteInteractor(db, logger, interactorOptions, nil)

	// 3. Initialize the Anansi Persistence service.
	// schema.FunctionMap{} is passed for custom Go functions (computed fields, custom filters).
	// Pass an empty map if no custom functions are used initially.
	persistenceService, err := persistence.NewPersistence(interactor, schema.FunctionMap{})
	if err != nil {
		logger.Fatal("Failed to initialize persistence service", zap.Error(err))
	}
	logger.Info("Anansi persistence service initialized successfully.")

