package main

import (
	"database/sql"
	"log"

	"github.com/asaidimu/go-anansi/v6/core/persistence"
	"github.com/asaidimu/go-anansi/v6/sqlite"
	_ "github.com/mattn/go-sqlite3" // SQLite driver
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
)

func main() {
	// Configure Zap logger (as shown in Persistence Service Initialization)
	config := zap.NewProductionConfig()
	config.Level = zap.NewAtomicLevelAt(zapcore.InfoLevel)
	config.EncoderConfig.EncodeTime = zapcore.ISO8601TimeEncoder
	config.EncoderConfig.TimeKey = "timestamp"

	logger, err := config.Build()
	if err != nil {
		log.Fatalf("Failed to initialize logger: %v", err)
	}
	defer logger.Sync()

	// 1. Open SQLite database connection
	db, err := sql.Open("sqlite3", "./api_database.db")
	if err != nil {
		logger.Fatal("Failed to open database", zap.Error(err))
	}
	defer db.Close()

	// 2. Initialize SQLite Interactor
	interactorOptions := sqlite.DefaultInteractorOptions()
	interactor := sqlite.NewSQLiteInteractor(db, logger, interactorOptions, nil)

	// 3. Initialize the Anansi Persistence service
	persistenceLayer, err := persistence.NewPersistence(interactor, nil)
	if err != nil {
		log.Fatal("Failed to initialize persistence:", err)
	}

	// 4. Create API server instance, passing the persistence layer and logger
	apiServer := NewAPIServer(persistenceLayer, logger)

	// 5. Start the API server on a specified address
	log.Println("Starting API server on :8080")
	if err := apiServer.Start(":8080"); err != nil {
		log.Fatal("Server failed:", err)
	}

	// To start with TLS:
	// if err := apiServer.StartTLS(":8443", "cert.pem", "key.pem"); err != nil {
	// 	log.Fatal("Server failed:", err)
	// }
}

